//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (arg) {
  let odrNo = "";
  if (arg == "DETAIL") {
    ed_odrNo.setValue(scwin.odrNo);
    odrNo = scwin.odrNo;
  } else if (arg == "REFERENCE") {
    odrNo = scwin.odrNo;
  } else if (arg == "INPUT") {
    arg = arg;
    //validation check     
    if (!(await $c.gus.cfValidate($p, [ed_odrNo]))) {
      return;
    }
    odrNo = ed_odrNo.getValue();
  } else {
    odrNo = ed_odrNo.getValue();
  }
  dma_queryCondition.set("odrNo", odrNo);

  //상세화면 데이타 Clear
  //scwin.f_Clear();		
  scwin.f_GetSellItemCd();
  ds_unitySelling.setJSON([]);
  await $c.sbm.execute($p, sbm_retrieveGeneralBillingOrder);
};

