scwin.f_cancelRow = function () {
  let row = ds_unitySelling.getRowPosition();
  if (ds_unitySelling.getRowStatus(row) == "C") {
    ds_unitySelling.removeRow(row);
    gr_unitySelling.setFocusedCell(row, 0);
  } else {
    if (ds_unitySelling.getTotalRow() == 1 && ds_unitySelling.getRowStatus(0) == "D") {
      $c.data.undoAll($p, ds_unitySelling);
    } else {
      ds_unitySelling.undoRow(row);
    }
  }
  scwin.rowvisibleCheck();
};
scwin.rowvisibleCheck = function () {
  for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
    if (ds_unitySelling.getRowStatus(i) == "D") {
      gr_unitySelling.setRowVisible(i, false);
    } else {
      gr_unitySelling.setRowVisible(i, true);
    }
  }
};

