//-------------------------------------------------------------------------
// 계산
//-------------------------------------------------------------------------
scwin.f_mathAmt = function (row, colid) {
  let sellVol = Number(ds_unitySelling.getCellData(row, "sellVol")); //수량	
  let sellUpr = Number(ds_unitySelling.getCellData(row, "sellUpr")); //매출단가
  let pchsUpr = Number(ds_unitySelling.getCellData(row, "pchsUpr")); //매입단가 
  let sellAmt = Number(ds_unitySelling.getCellData(row, "sellAmt")); //매출금액
  let sellAmtFcrc = Number(ds_unitySelling.getCellData(row, "sellAmtFcrc")); //매출금액
  let pchsAmt = Number(ds_unitySelling.getCellData(row, "pchsAmt")); //매입금액
  let vatAmt = Number(ds_unitySelling.getCellData(row, "vatAmt")); //매출부가세
  let pchsVatAmt = Number(ds_unitySelling.getCellData(row, "pchsVatAmt")); //매입부가세
  let totSellAmt = "0"; //매출합계
  let totPchsAmt = "0"; //매입합계
  let adptExchRt = ed_adptExchRt.getValue(); //환율

  let sellAmtTot = 0;
  let sellAmtFcrcTot = 0;
  let vatAmtTot = 0;
  let totSellAmtTot = 0;
  let pchsAmtTot = 0;
  let pchsVatAmtTot = 0;
  let totPchsAmtTot = 0;
  if (acb_crcCd.getValue() == "KRW") {
    switch (colid) {
      case "sellVol":
        sellAmt = sellVol * sellUpr;
        pchsAmt = sellVol * pchsUpr;
        break;
      case "sellUpr":
        sellAmt = sellVol * sellUpr;
        break;
      case "pchsUpr":
        pchsAmt = sellVol * pchsUpr;
        break;
      case "sellAmt":
        if (sellVol != 0) {
          sellUpr = Math.floor(sellAmt / sellVol);
        } else {
          sellUpr = "0";
        }
        break;
      case "pchsAmt":
        if (sellVol != 0) {
          pchsUpr = Math.floor(sellAmt / sellVol);
        } else {
          pchsUpr = "0";
        }
        break;
    }
    if (!(colid == "vatAmt" || colid == "pchsVatAmt")) {
      if (ds_unitySelling.getCellData(row, "sellYn") == "1") {
        vatAmt = acb_sellTaxnClsCd.getValue() == "01" || acb_sellTaxnClsCd.getValue() == "04" ? Math.round(sellAmt / 10) : 0;
        pchsVatAmt = acb_pchsTaxnClsCd.getValue() == "01" || acb_sellTaxnClsCd.getValue() == "04" ? Math.round(pchsAmt / 10) : 0;
      } else {
        vatAmt = 0;
        pchsVatAmt = 0;
      }
    }
  } else {
    switch (colid) {
      case "sellVol":
        sellAmtFcrc = sellVol * sellUpr;
        pchsAmt = sellVol * pchsUpr;
        break;
      case "sellUpr":
        sellAmtFcrc = sellVol * sellUpr;
        break;
      case "pchsUpr":
        pchsAmt = sellVol * pchsUpr;
        break;
      case "sellAmtFcrc":
        if (sellVol != 0) {
          sellUpr = Math.floor(sellAmtFcrc / sellVol * 100) / 100;
        } else {
          sellUpr = 0;
        }
        break;
      case "pchsAmt":
        if (sellVol != 0) {
          pchsUpr = Math.floor(sellAmtFcrc / sellVol * 100) / 100;
        } else {
          pchsUpr = 0;
        }
        break;
    }
    if (colid != "sellAmt") {
      sellAmt = Math.floor(sellAmtFcrc * adptExchRt);
      vatAmt = 0;
    }
    if (gr_unitySelling.getHeaderValue("column23") == '매입(부)') {
      if (ds_unitySelling.getCellData(row, "sellYn") == 1) {
        pchsVatAmt = acb_pchsTaxnClsCd.getValue() == "01" ? Math.round(pchsAmt / 10) : 0;
      } else {
        pchsVatAmt = 0;
      }
    }
  }
  totSellAmt = Number(sellAmt) + Number(vatAmt);
  totPchsAmt = Number(pchsAmt) + Number(pchsVatAmt);
  ds_unitySelling.setCellData(row, "sellVol", sellVol); //수량	
  ds_unitySelling.setCellData(row, "sellUpr", Number(sellUpr)); //매출단가
  ds_unitySelling.setCellData(row, "pchsUpr", pchsUpr); //매입단가 
  ds_unitySelling.setCellData(row, "sellAmt", sellAmt); //매출금액
  ds_unitySelling.setCellData(row, "sellAmtFcrc", sellAmtFcrc); //매출금액
  ds_unitySelling.setCellData(row, "pchsAmt", pchsAmt); //매입금액
  ds_unitySelling.setCellData(row, "vatAmt", vatAmt); //매출부가세
  ds_unitySelling.setCellData(row, "pchsVatAmt", pchsVatAmt); //매입부가세
  ds_unitySelling.setCellData(row, "totSellAmt", totSellAmt); //매출합계
  ds_unitySelling.setCellData(row, "totPchsAmt", totPchsAmt); //매입합계

  scwin.f_SumAmt();
};

