//-------------------------------------------------------------------------
// 금액계산
//-------------------------------------------------------------------------
scwin.f_SumAmt = function () {
  let sellAmtFcrc = 0;
  let sellAmt = 0;
  let totSellAmt = 0;
  let pchsAmt = 0;
  let totPchsAmt = 0;
  let fireInsrRateAmt = 0;
  for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
    if (ds_unitySelling.getCellData(i, "sellYn") == 1) {
      sellAmtFcrc = Number(Number(sellAmtFcrc) + Number(ds_unitySelling.getCellData(i, "sellAmtFcrc")));
      sellAmt = Number(Number(sellAmt) + Number(ds_unitySelling.getCellData(i, "sellAmt")));
      totSellAmt = Number(Number(totSellAmt) + Number(ds_unitySelling.getCellData(i, "totSellAmt")));
      pchsAmt = Number(Number(pchsAmt) + Number(ds_unitySelling.getCellData(i, "pchsAmt")));
      totPchsAmt = Number(Number(totPchsAmt) + Number(ds_unitySelling.getCellData(i, "totPchsAmt")));
      let totSellAmtcheck = Number(ds_unitySelling.getCellData(i, "totSellAmt"));
      let sellCheck = Number(ds_unitySelling.getCellData(i, "sellAmt"));
      let totPchsAmtCheck = Number(ds_unitySelling.getCellData(i, "totPchsAmt"));
      let pchsAmtCheck = Number(ds_unitySelling.getCellData(i, "pchsAmt"));
      ds_unitySelling.setCellData(i, "vatAmt", Number(totSellAmtcheck - sellCheck));
      ds_unitySelling.setCellData(i, "pchsVatAmt", Number(totPchsAmtCheck - pchsAmtCheck));
    } else {
      fireInsrRateAmt = fireInsrRateAmt + Number(ds_unitySelling.getCellData(i, "sellAmt"));
      ds_unitySelling.setCellData(i, "vatAmt", 0);
      ds_unitySelling.setCellData(i, "pchsVatAmt", 0);
    }
  }
  ed_sellAmtFcrc.setValue(Number(sellAmtFcrc));
  ed_sellAmt.setValue(Number(sellAmt));
  ed_totSellAmt.setValue(Number(totSellAmt));
  ed_vatAmt.setValue(Number(totSellAmt - sellAmt));
  ed_pchsAmt.setValue(Number(pchsAmt));
  ed_totPchsAmt.setValue(Number(totPchsAmt));
  ed_pchsVatAmt.setValue(Number(totPchsAmt - pchsAmt));
  ed_fireInsrRateAmt.setValue(Number(fireInsrRateAmt));
};

//-------------------------------------------------------------------------
// 환율 계산
//-------------------------------------------------------------------------
scwin_mathAdptExchRt = function () {
  let sellAmtFcrc = 0;
  let sellAmt = 0;
  let adptExchRt = ed_adptExchRt.getValue();
  let sellAmtTot = 0;
  for (let i = 1; i <= ds_unitySelling.getTotalRow(); i++) {
    sellAmtFcrc = ds_unitySelling.getCellData(i, "sellAmtFcrc"); //매출금액
    sellAmt = ds_unitySelling.getCellData(i, "sellAmt"); //매출금액

    sellAmt = Math.floor(sellAmtFcrc * adptExchRt);
    let totSellAmt = Number(sellAmt);
    ds_unitySelling.setCellData(i, "sellAmt", sellAmt); //매출금액
    sellAmtTot = sellAmtTot + sellAmt;
  }
  ed_sellAmt.setValue(sellAmtTot);
  ed_totSellAmt.setValue(sellAmtTot);
};

