scwin.onPopupEvent = async function () {
  let oldIndex = gr_unitySelling.getColumnID(scwin.oldIndex);
  let colid = gr_unitySelling.getColumnID(scwin.oldIndex);
  let row = gr_unitySelling.getFocusedRowIndex();
  //팝업창 띄우기
  if (colid == "sellCommNoDesc") {
    if (ds_unitySelling.getCellData(row, "sellGoodsPatternCd") == "02" || ds_unitySelling.getCellData(row, "sellGoodsPatternCd") == "01") {
      scwin.f_Popup(1);
    } else if (ds_unitySelling.getCellData(row, "sellGoodsPatternCd") == "03") {
      scwin.f_Popup(2);
    } else if (ds_unitySelling.getCellData(row, "sellGoodsPatternCd") == "05") {
      scwin.f_Popup(3);
    } else {
      return;
    }
  } else if (colid == "vehclNo") {
    //차량번호
    scwin.f_Popup(4);
  } else if (colid == "reqClntNm") {
    //요청거래처
    scwin.f_Popup(5);
  }
};

