scwin.udc_grid_common_Callback = function (rtnList) {
  let row = gr_unitySelling.getFocusedRowIndex();
  let colid = gr_unitySelling.getColumnID(scwin.oldIndex);
  if (colid == "sellCommNoDesc") {
    if (rtnList != null && rtnList[0] != "N/A") {
      //return value Assign
      ds_unitySelling.setCellData(row, "sellCommNoDesc", rtnList[0]); //품명코드															
      ds_unitySelling.setCellData(row, "sellCommNoQry", rtnList[0]); //품명코드
      ds_unitySelling.setCellData(row, "sellCommNm", rtnList[1]); //품명명					
    }
  } else if (colid == "sellCommNoDesc") {
    if (rtnList != null && rtnList[0] != "N/A") {
      //return value Assign
      ds_unitySelling.setCellData(row, "sellCommNoDesc", rtnList[0]); //작업도구코드															
      ds_unitySelling.setCellData(row, "sellCommNoQry", rtnList[0]); //작업도구코드
      ds_unitySelling.setCellData(row, "sellCommNm", rtnList[1]); //작업도구명					
    }
  } else if (colid == "vehclNo") {
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_unitySelling.setCellData(row, "vehclNo", rtnList[1]); //차량번호
    } else {
      ds_unitySelling.setCellData(row, "vehclNo", "");
    }
  } else if (colid == "reqClntNm") {
    if (rtnList != null && rtnList[0] != "N/A") {
      ds_unitySelling.setCellData(row, "reqClntNo", rtnList[0]);
      ds_unitySelling.setCellData(row, "reqClntNm", rtnList[1]);
    } else {
      ds_unitySelling.setCellData(row, "reqClntNo", "");
      ds_unitySelling.setCellData(row, "reqClntNm", "");
    }
  }
};

