scwin.getOdrChk = async function () {
  let odrNo = ed_odrNo.getValue();
  // SELECT 절
  let param1 = " (SELECT COUNT(*) FROM TB_FS422 WHERE ODR_NO = '" + odrNo + "')	 as COL1 " //위수탁관리비
  + ", (SELECT COUNT(*) FROM TB_FS425 WHERE ODR_NO = '" + odrNo + "')		 as COL2 " //장기용차관리비
  + ",''			 as COL3 " + ",''			 as COL4 " + ",''			 as COL5 " + ",''			 as COL6 " + ",''			 as COL7 " + ",''			 as COL8 " + ",''			 as COL9 " + ",''			 as COL10 ";

  // 대상테이블
  let param2 = "DUAL";
  dma_orderChk.set("sysCd", "CommonEBC");
  dma_orderChk.set("queryId", "dinymicQueryTest2");
  dma_orderChk.set("param1", param1);
  dma_orderChk.set("param2", param2);
  // ds_orderChk.DataId = 
  //     "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest2" + "&param1=" + param1 
  //                                                                                     + "&param2=" + param2 
  //                                                                                 ;
  // ds_orderChk.Reset();

  let result = await $c.sbm.execute($p, sbm_orderChk);
  if (result.responseJSON.resultDataSet[0].Msg == "SUCC") {
    if (ds_orderChk.getCellData(0, "col1") != "0") {
      $c.win.alert($p, "일반청구 오더가 아닙니다. <br>위수탁관리비화면에서 삭제진행하시길 바랍니다.");
      result = false;
    } else if (ds_orderChk.getCellData(0, "col2") != "0") {
      $c.win.alert($p, "일반청구 오더가 아닙니다. <br>장기용차관리비화면에서 삭제진행하시길 바랍니다.");
      result = false;
    } else {
      result = true;
    }
  }
  return result;
};

