// 저장
//-------------------------------------------------------------------------
scwin.btn_f_Save_onClick = async function () {
  var validArry = [{
    id: "sellSeq",
    name: "매출순번",
    mandatory: true,
    maxlength: 3,
    key: true
  }, {
    id: "sellItemCd",
    name: "매출항목",
    mandatory: true,
    maxlength: 4,
    key: true
  }, {
    id: "bizDomCd",
    name: "사업영역",
    mandatory: true,
    maxlength: 3
  }, {
    id: "sellGoodsPatternCd",
    name: "구분",
    mandatory: true,
    maxlength: 2
  }, {
    id: "reqClntNo",
    name: "요청거래처",
    mandatory: true,
    length: 6
  }];
  let gridName = "통합 매출입";
  if (rd_pchsCreatYn.getValue() == "1") {
    if (!(await $c.gus.cfValidate($p, [ed_bilgLodeptCd, ed_bilgClntNo, ed_sellLodeptCd, ed_pchsDeptCd, ed_reqClntNo]))) return;
  } else {
    if (!(await $c.gus.cfValidate($p, [ed_bilgLodeptCd, ed_bilgClntNo, ed_sellLodeptCd, ed_reqClntNo]))) return;
  }
  if (acb_crcCd.getValue() != "KRW") {
    if (!(await $c.gus.cfValidate($p, [ed_adptExchRt]))) return;
  }
  if (ds_unitySelling.getRowCount() < 1) {
    $c.win.alert($p, scwin.MSG_FS_WRN_020);
    return;
  }
  if ((await ds_order.getModifiedIndex().length) == 0 && ds_certiCommon.getModifiedIndex().length == 0 && ds_purchaseCerti.getModifiedIndex().length == 0 && ds_unitySelling.getModifiedIndex().length == 0) {
    $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_001, "일반청구오더 관리"));
    return;
  }
  if (!(await $c.gus.cfValidateGrid($p, gr_unitySelling, null, null, validArry, gridName))) {
    return;
  }
  //구분이 CNTR-NO 일경우 Validation 체크
  for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
    if (ds_unitySelling.getCellData(i, "sellGoodsPatternCd") != "09") {
      if (ds_unitySelling.getCellData(i, "sellCommNoDesc") == "") {
        $c.win.alert($p, scwin.MSG_FS_WRN_022);
        gr_unitySelling.setFocusedCell(i, "sellCommNoDesc");
        return;
      }
    }
  }

  //구분이 CNTR-NO 일경우 Validation 체크
  for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
    if (ds_unitySelling.getCellData(i, "sellGoodsPatternCd") == "01") {
      if (ds_unitySelling.getCellData(i, "cntrNo") == "" || ds_unitySelling.getCellData(i, "cntrNo") == null) {
        $c.win.alert($p, scwin.MSG_FS_WRN_021);
        gr_unitySelling.setFocusedCell(i, "cntrNo");
        return;
      }
    }
  }
  if (!(await $c.win.confirm($p, MSG_CM_CRM_001))) {
    return;
  }
  if (acb_sellTaxnClsCd.getValue() == "01" || acb_sellTaxnClsCd.getValue() == "04") {
    for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
      if (ds_unitySelling.getCellData(i, "vatAmt") == 0) {
        $c.win.alert($p, "매출순번 " + (i + 1) + "번의 부가세를 입력해주세요.");
        return;
      }
    }
  }
  if (acb_sellTaxnClsCd.getValue() == "02" || acb_sellTaxnClsCd.getValue() == "03") {
    for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
      if (ds_unitySelling.getCellData(i, "vatAmt") > 0) {
        $c.win.alert($p, "매출순번 " + (i + 1) + "번의 부가세를 확인해주세요.");
        return;
      }
    }
  }

  //매입생성여부값이 선택된경우 매출입항목이 운송료,하불임인경우 차량번호 체크
  //2014.08.29 hurrah
  //alert(rd_pchsCreatYn.CodeValue);
  if (rd_pchsCreatYn.getValue() == 1) {
    for (i = 0; i < ds_unitySelling.getTotalRow(); i++) {
      //운송료,하불임만
      if (ds_unitySelling.getCellData(i, "sellItemCd") == "0010" || ds_unitySelling.getCellData(i, "sellItemCd") == "0131") {
        if ($c.gus.cfIsNull($p, ds_unitySelling.getCellData(i, "vehclNo")) || ds_unitySelling.getCellData(i, "vehclNo") == "") {
          $c.win.alert($p, "매출순번 " + (i + 1) + "번의 차량번호를 입력해주세요.");
          gr_unitySelling.setFocusedCell(i, "vehclNo");
          return;
        }
      }
    }
  }
  console.log("저장전");
  //오더정보
  await scwin.f_OrderDataSet();
  //매출정보        	
  await scwin.f_CertiCommonDataSet();
  //매입정보        	
  await scwin.f_PurchaseCertiDataSet();
  //통합매출입정보
  await scwin.f_UnitySellingDataSet();
  console.log("단계5");
  await $c.sbm.execute($p, sbm_registGeneralBillingOrder);
};

